svg.script:
class PerlinNoise {
  constructor(seed = Math.random() * 10000) {
    this.p = [];
    for (let i = 0; i < 256; i++) this.p[i] = i;
    let n = seed;
    for (let i = 255; i > 0; i--) {
      n = (n * 16807) % 2147483647;
      const j = n % (i + 1);
      [this.p[i], this.p[j]] = [this.p[j], this.p[i]];
    }
    this.p = this.p.concat(this.p);
  }
  fade(t) { return t * t * t * (t * (t * 6 - 15) + 10); }
  lerp(a, b, t) { return a + t * (b - a); }
  grad(hash, x) { return (hash & 1) === 0 ? x : -x; }
  noise1D(x) {
    const xi = Math.floor(x) & 255;
    const xf = x - Math.floor(x);
    const u = this.fade(xf);
    return this.lerp(this.grad(this.p[xi], xf), this.grad(this.p[xi + 1], xf - 1), u);
  }
}

const clauditoX = 100;
const clauditoY = 18;

// Tentacle configs - each has anchor, rest position, and noise generators
const tentacles = [
  {
    el: document.getElementById('leg0'),
    // Anchor at body (▘ position)
    anchorX: clauditoX - 18,
    anchorY: clauditoY + 34,
    // General area this tentacle covers
    restX: 55,
    restY: 90,
    // Multiple noise generators for different aspects
    noise: {
      curl1: new PerlinNoise(1),
      curl2: new PerlinNoise(11),
      sway: new PerlinNoise(21),
      reach: new PerlinNoise(31),
      tipX: new PerlinNoise(41),
      tipY: new PerlinNoise(51)
    },
    phase: 0
  },
  {
    el: document.getElementById('leg1'),
    anchorX: clauditoX - 10,
    anchorY: clauditoY + 34,
    restX: 80,
    restY: 92,
    noise: {
      curl1: new PerlinNoise(2),
      curl2: new PerlinNoise(12),
      sway: new PerlinNoise(22),
      reach: new PerlinNoise(32),
      tipX: new PerlinNoise(42),
      tipY: new PerlinNoise(52)
    },
    phase: 1.3
  },
  {
    el: document.getElementById('leg2'),
    anchorX: clauditoX + 10,
    anchorY: clauditoY + 34,
    restX: 120,
    restY: 92,
    noise: {
      curl1: new PerlinNoise(3),
      curl2: new PerlinNoise(13),
      sway: new PerlinNoise(23),
      reach: new PerlinNoise(33),
      tipX: new PerlinNoise(43),
      tipY: new PerlinNoise(53)
    },
    phase: 2.7
  },
  {
    el: document.getElementById('leg3'),
    anchorX: clauditoX + 18,
    anchorY: clauditoY + 34,
    restX: 145,
    restY: 90,
    noise: {
      curl1: new PerlinNoise(4),
      curl2: new PerlinNoise(14),
      sway: new PerlinNoise(24),
      reach: new PerlinNoise(34),
      tipX: new PerlinNoise(44),
      tipY: new PerlinNoise(54)
    },
    phase: 4.1
  }
];

let time = 0;
let lastTime = performance.now();

function animate(currentTime) {
  const deltaTime = (currentTime - lastTime) / 1000;
  lastTime = currentTime;
  time += deltaTime;

  tentacles.forEach(t => {
    const p = t.phase;
    const n = t.noise;

    // Tip position - wanders around rest position
    const tipWanderX = n.tipX.noise1D(time * 0.7 + p) * 25;
    const tipWanderY = n.tipY.noise1D(time * 0.9 + p) * 15;
    const tipX = t.restX + tipWanderX;
    const tipY = t.restY + tipWanderY;

    // Calculate base direction vector
    const dx = tipX - t.anchorX;
    const dy = tipY - t.anchorY;
    const dist = Math.sqrt(dx * dx + dy * dy);

    // Perpendicular vector for curl offset
    const perpX = -dy / dist;
    const perpY = dx / dist;

    // Control points along the tentacle with curl
    // First control point (1/3 along)
    const curl1 = n.curl1.noise1D(time * 1.5 + p) * 20;
    const sway1 = n.sway.noise1D(time * 0.8 + p) * 8;
    const cp1x = t.anchorX + dx * 0.33 + perpX * curl1 + sway1;
    const cp1y = t.anchorY + dy * 0.33 + perpY * curl1;

    // Second control point (2/3 along)
    const curl2 = n.curl2.noise1D(time * 1.8 + p + 10) * 25;
    const sway2 = n.sway.noise1D(time * 1.1 + p + 5) * 10;
    const cp2x = t.anchorX + dx * 0.66 + perpX * curl2 + sway2;
    const cp2y = t.anchorY + dy * 0.66 + perpY * curl2;

    // Build cubic bezier path
    const path = `M ${t.anchorX} ${t.anchorY} C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${tipX} ${tipY}`;
    t.el.setAttribute('d', path);
  });

  requestAnimationFrame(animate);
}

requestAnimationFrame(animate);
